import * as React from 'react';
import type { RadioProps } from './radio';
import Radio from './radio';
import useRadioGroupContext from './useRadioGroupContext';
import { useCssScope } from '../config-provider/hooks';
import { isNonNullable } from '../util';

import './style';

export default React.forwardRef<HTMLInputElement, Omit<RadioProps, 'optionType'>>((props, ref) => {
  const radioGroupContext = useRadioGroupContext();
  const registerBOT = radioGroupContext?.registerBOT;
  const unregisterBOT = radioGroupContext?.unregisterBOT;
  const cssScope = useCssScope('radio-button');
  const { ...radioProps } = props;
  /* istanbul ignore else  */
  if (radioGroupContext) {
    radioProps.checked = props.value === radioGroupContext.value;
    radioProps.disabled = props.disabled || radioGroupContext.disabled;
  }
  React.useLayoutEffect(() => {
    if (isNonNullable(props.value)) {
      const v = props.value;
      registerBOT?.(v);
      return () => {
        unregisterBOT?.(v);
      };
    }
  }, [props.value, registerBOT, unregisterBOT]);
  return <Radio prefixCls={cssScope()} {...radioProps} optionType="button" ref={ref} />;
});
